        for i in range(9):
            if board[row][i] == num:
                return False
        for i in range(9):
            if board[i][col] == num:
                return False
        for i in range(3 * (row // 3)):
            for j in range(3 * (col // 3)):
                if board[i][j] == num:
                    return False
        return True

    def solve(self, board):
        for i in range(9):
            for j in range(9):
                if board[i][j] == 0:
                    for k in range(1, 10):
                        if self.isValid(board, i, j, k):
                            board[i][j] = k
                            if self.solve(board):
