class Solution {
public:
    bool isValid(vector<vector<int>>& board, int row, int col, int num)
    {
        // Check the row
        for (int i = 0; i < 9; i++)
        {
            if (board[row][i] == num)
                return false;
        }

        // Check the column
        for (int i = 0; i < 9; i++)
        {
            if (board[i][col] == num)
                return false;
        }

        // Check the 3x3 box
        int boxRow = row - row % 3;
        int boxCol = col - col % 3;
        for (int i = 0; i < 3; i++)
        {
            for (int j = 0; j < 3; j++)
            {
                if (board[boxRow + i][boxCol + j] == num)
                    return false;
            }
        }

        return true;
    }

    bool solve(vector<vector<int>>& board)
    {
        for (int i = 0; i < 9; i++)
        {
            for (int j = 0; j < 9; j++)
            {
                if (board[i][j] == 0)
                {
                    for (int k = 1; k <= 9; k++)
                    {
                        if (isValid(board, i, j, k))
                        {
                            board[i][j] = k;
                            if (solve(board))
                                return true;
                        }
                    }
                    return false;
                }
            }
        }
        return true;
    }
};

int main() {
    // Read the input
    int n;
    std::cin >> n;
    vector<vector<int>> board(9, vector<int>(9));
    for (int i = 0; i < 9; i++)
    {
        for (int j = 0; j < 9; j++)
        {
            std::cin >> board[i][j];
        }
    }

    Solution solution;
    std::cout << (solution.solve(board) ? "true" : "false") << std::endl;
    return 0;
}
